insert into apis (slug, name, emoji, tagline, description_md, category_id, docs_url, base_url, auth_type, check_tier, https, cors_verified, free_tier_notes, rate_limit_notes, requires_card, commercial_use, data_license, status, added_at, monitored_since, tombstoned_at, epitaph) select 'world-news-api', 'World News API', '📰', 'Global news search in 86+ languages with semantic tagging', 'World News API indexes thousands of sources across 210+ countries with semantic entity tags, sentiment, geo filters, and newspaper front pages. Free tier: 50 points/day with an API key from worldnewsapi.com.', c.id, 'https://worldnewsapi.com/docs', 'https://api.worldnewsapi.com', 'apiKey', 'endpoint', 1, 1, 'Free — 50 API points/day', '50 points/day on free plan', 0, 'unclear', 'Unverified', 'unmonitored', '2026-07-05', NULL, NULL, NULL from categories c where c.slug = 'data' and not exists (select 1 from apis where slug = 'world-news-api');
insert into endpoints (api_id, method, url_template, sample_params_json, description, active) select a.id, 'GET', 'https://api.worldnewsapi.com/search-news?text=technology&number=1', NULL, 'Global news search in 86+ languages with semantic tagging', 1 from apis a where a.slug = 'world-news-api' and not exists (select 1 from endpoints e where e.api_id = a.id and e.method = 'GET' and e.url_template = 'https://api.worldnewsapi.com/search-news?text=technology&number=1');
insert into endpoints (api_id, method, url_template, sample_params_json, description, active) select a.id, 'GET', 'https://api.worldnewsapi.com/search-news?limit=5', NULL, 'Search News — documented GET route.', 0 from apis a where a.slug = 'world-news-api' and not exists (select 1 from endpoints e where e.api_id = a.id and e.method = 'GET' and e.url_template = 'https://api.worldnewsapi.com/search-news?limit=5');
insert into endpoints (api_id, method, url_template, sample_params_json, description, active) select a.id, 'GET', 'https://api.worldnewsapi.com/search-news?page=1', NULL, 'Search News — documented GET route.', 0 from apis a where a.slug = 'world-news-api' and not exists (select 1 from endpoints e where e.api_id = a.id and e.method = 'GET' and e.url_template = 'https://api.worldnewsapi.com/search-news?page=1');
insert into endpoints (api_id, method, url_template, sample_params_json, description, active) select a.id, 'GET', 'https://api.worldnewsapi.com/', NULL, 'API root or index route.', 0 from apis a where a.slug = 'world-news-api' and not exists (select 1 from endpoints e where e.api_id = a.id and e.method = 'GET' and e.url_template = 'https://api.worldnewsapi.com/');
insert into endpoints (api_id, method, url_template, sample_params_json, description, active) select a.id, 'GET', 'https://api.worldnewsapi.com/top-news?headlines-only=true&source-country=', NULL, 'Top News — documented GET route.', 0 from apis a where a.slug = 'world-news-api' and not exists (select 1 from endpoints e where e.api_id = a.id and e.method = 'GET' and e.url_template = 'https://api.worldnewsapi.com/top-news?headlines-only=true&source-country=');
